    <script>
        // 初始化数据
        const STORAGE_KEY = 'nutri_track_data';
        const DEFAULT_TARGETS = {
            calories: 2000,
            protein: 100,
            fat: 65,
            carbs: 250
        };

        let foods = [];

        // 加载数据
        function loadData() {
            const stored = localStorage.getItem(STORAGE_KEY);
            foods = stored ? JSON.parse(stored) : [];
            renderFoodLog();
            updateStats();
        }

        // 保存数据
        function saveData() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(foods));
        }

        // 添加食物
        function addFood() {
            const name = document.getElementById('foodName').value.trim();
            const grams = parseFloat(document.getElementById('foodGrams').value);
            const calories = parseFloat(document.getElementById('foodCalories').value);

            if (!name || !grams || !calories) {
                alert('Please fill in all fields');
                return;
            }

            // 简单营养计算（基于热量）
            const protein = Math.round((calories * 0.3) / 4 * 10) / 10;  // 30% calories from protein
            const fat = Math.round((calories * 0.3) / 9 * 10) / 10;      // 30% calories from fat
            const carbs = Math.round((calories * 0.4) / 4 * 10) / 10;    // 40% calories from carbs

            foods.push({
                id: Date.now(),
                name,
                grams,
                calories,
                protein,
                fat,
                carbs,
                timestamp: new Date().toLocaleTimeString()
            });

            saveData();
            renderFoodLog();
            updateStats();

            // 清空输入框
            document.getElementById('foodName').value = '';
            document.getElementById('foodGrams').value = '';
            document.getElementById('foodCalories').value = '';
            document.getElementById('foodName').focus();
        }

        // 删除食物
        function deleteFood(id) {
            foods = foods.filter(f => f.id !== id);
            saveData();
            renderFoodLog();
            updateStats();
        }

        // 渲染食物表格
        function renderFoodLog() {
            const tbody = document.getElementById('foodTableBody');

            if (foods.length === 0) {
                tbody.innerHTML = '<tr class="empty-state"><td colspan="7">No food entries yet. Add your first meal above!</td></tr>';
                return;
            }

            tbody.innerHTML = foods.map(food => `
                <tr>
                    <td><strong>${food.name}</strong></td>
                    <td>${food.grams}g</td>
                    <td><strong>${food.calories}</strong></td>
                    <td>${food.protein}g</td>
                    <td>${food.fat}g</td>
                    <td>${food.carbs}g</td>
                    <td><button class="delete-btn" onclick="deleteFood(${food.id})">Delete</button></td>
                </tr>
            `).join('');
        }

        // 更新统计数据
        function updateStats() {
            const totals = foods.reduce((acc, food) => ({
                calories: acc.calories + food.calories,
                protein: acc.protein + food.protein,
                fat: acc.fat + food.fat,
                carbs: acc.carbs + food.carbs
            }), { calories: 0, protein: 0, fat: 0, carbs: 0 });

            // 更新卡路里
            const caloriesPercent = Math.min(100, (totals.calories / DEFAULT_TARGETS.calories) * 100);
            document.getElementById('caloriesValue').textContent = Math.round(totals.calories);
            document.getElementById('caloriesInfo').textContent = `${Math.round(caloriesPercent)}% of ${DEFAULT_TARGETS.calories} kcal`;
            document.getElementById('caloriesBar').style.width = caloriesPercent + '%';

            // 更新蛋白质
            const proteinPercent = Math.min(100, (totals.protein / DEFAULT_TARGETS.protein) * 100);
            document.getElementById('proteinValue').textContent = totals.protein.toFixed(1);
            document.getElementById('proteinInfo').textContent = `${Math.round(proteinPercent)}% of ${DEFAULT_TARGETS.protein}g`;
            document.getElementById('proteinBar').style.width = proteinPercent + '%';

            // 更新脂肪
            const fatPercent = Math.min(100, (totals.fat / DEFAULT_TARGETS.fat) * 100);
            document.getElementById('fatValue').textContent = totals.fat.toFixed(1);
            document.getElementById('fatInfo').textContent = `${Math.round(fatPercent)}% of ${DEFAULT_TARGETS.fat}g`;
            document.getElementById('fatBar').style.width = fatPercent + '%';

            // 更新碳水
            const carbsPercent = Math.min(100, (totals.carbs / DEFAULT_TARGETS.carbs) * 100);
            document.getElementById('carbsValue').textContent = totals.carbs.toFixed(1);
            document.getElementById('carbsInfo').textContent = `${Math.round(carbsPercent)}% of ${DEFAULT_TARGETS.carbs}g`;
            document.getElementById('carbsBar').style.width = carbsPercent + '%';
        }

        // 登出
        function logout() {
            if (confirm('Are you sure you want to logout?')) {
                alert('Logged out successfully!');
            }
        }

        // 页面加载
        window.addEventListener('DOMContentLoaded', loadData);

        // 键盘快捷键
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Enter' && document.getElementById('foodName') === document.activeElement) {
                addFood();
            }
        });
    </script>
</body>
</html>
