    <script>
        // 初始化数据
        let meals = JSON.parse(localStorage.getItem(\'meals\')) || [
            { name: \'鸡蛋\', amount: 100, calories: 155, protein: 13, carbs: 1.1, fat: 11 },
            { name: \'米饭\', amount: 150, calories: 195, protein: 4, carbs: 43, fat: 0.3 }
        ];

        // 页面初始化
        function init() {
            renderMealTable();
            updateStats();
        }

        // 渲染食物表格
        function renderMealTable() {
            const tbody = document.getElementById(\'meal-table-body\');
            tbody.innerHTML = meals.map((meal, idx) => `
                <tr>
                    <td>${meal.name}</td>
                    <td>${meal.amount}</td>
                    <td>${meal.calories}</td>
                    <td>${meal.protein || 0}</td>
                    <td>${meal.carbs || 0}</td>
                    <td>${meal.fat || 0}</td>
                    <td><button class="delete-btn" onclick="deleteMeal(${idx})">删除</button></td>
                </tr>
            `).join(\'\');
        }

        // 添加食物
        function addFood() {
            const name = document.getElementById(\'food-name\').value.trim();
            const amount = parseInt(document.getElementById(\'food-amount\').value) || 0;
            const calories = parseInt(document.getElementById(\'food-calories\').value) || 0;

            if (!name || amount <= 0 || calories <= 0) {
                alert(\'请填写完整信息\');
                return;
            }

            meals.push({ name, amount, calories, protein: 0, carbs: 0, fat: 0 });
            localStorage.setItem(\'meals\', JSON.stringify(meals));
            document.getElementById(\'food-name\').value = \'\';
            document.getElementById(\'food-amount\').value = \'\';
            document.getElementById(\'food-calories\').value = \'\';
            renderMealTable();
            updateStats();
        }

        // 删除食物
        function deleteMeal(idx) {
            meals.splice(idx, 1);
            localStorage.setItem(\'meals\', JSON.stringify(meals));
            renderMealTable();
            updateStats();
        }

        // 更新统计信息
        function updateStats() {
            const totalCal = meals.reduce((sum, m) => sum + m.calories, 0);
            const totalProtein = meals.reduce((sum, m) => sum + (m.protein || 0), 0);
            const totalCarbs = meals.reduce((sum, m) => sum + (m.carbs || 0), 0);
            const totalFat = meals.reduce((sum, m) => sum + (m.fat || 0), 0);

            // 更新显示
            document.getElementById(\'cal-value\').textContent = `${totalCal} / 2000`;
            document.getElementById(\'protein-value\').textContent = `${totalProtein}g / 100g`;
            document.getElementById(\'carbs-value\').textContent = `${totalCarbs}g / 250g`;
            document.getElementById(\'fat-value\').textContent = `${totalFat}g / 65g`;

            // 更新进度条
            document.getElementById(\'cal-progress\').style.width = Math.min(totalCal / 20, 100) + \'%\';
            document.getElementById(\'protein-progress\').style.width = Math.min(totalProtein / 100 * 100, 100) + \'%\';
            document.getElementById(\'carbs-progress\').style.width = Math.min(totalCarbs / 250 * 100, 100) + \'%\';
            document.getElementById(\'fat-progress\').style.width = Math.min(totalFat / 65 * 100, 100) + \'%\';
        }

        // 切换页面
        function switchPage(page) {
            document.querySelectorAll(\'.menu-item\').forEach(item => item.classList.remove(\'active\'));
            event.target.classList.add(\'active\');
        }

        // 登出
        function logout() {
            if (confirm(\'确定要登出吗?\')) {
                alert(\'已登出\');
            }
        }

        // 初始化
        window.addEventListener(\'DOMContentLoaded\', init);
    </script>
</body>
